def slidingWindowMaximum(data):
    parts = data.splitlines()
    nums = list(map(int, parts[0].split()))
    k = int(parts[1])

    n = len(nums)
    if n == 0 or k == 0:
        return ""

    max_values = []

    for i in range(n - k + 1):
        max_in_window = nums[i]
        for j in range(1, k):
            if nums[i + j] > max_in_window:
                max_in_window = nums[i + j]
        max_values.append(max_in_window)

    return ' '.join(map(str, max_values))

