package main

import (
    "container/list"
)

func slidingWindowMaximum(data []int) []int {
    n := len(data)
    if n == 0 {
        return []int{}
    }

    result := []int{}
    deque := list.New()

    for i := 0; i < n; i++ {
        // Remove elements not in the current window
        for deque.Len() > 0 && deque.Front().Value.(int) < i-2 {
            deque.Remove(deque.Front())
        }
        // Remove elements smaller than the current element
        for deque.Len() > 0 && data[deque.Back().Value.(int)] < data[i] {
            deque.Remove(deque.Back())
        }
        // Add current element index
        deque.PushBack(i)
        // Add to result if we have filled the first window
        if i >= 2 {
            result = append(result, data[deque.Front().Value.(int)])
        }
    }
    return result
}

