public class Solution {
    public List<Integer> slidingWindowMaximum(int[] data) {
        int n = data.Length;
        if (n == 0) return new List<Integer>();
        int k = 3; // Assuming the window size is 3 for this example
        List<Integer> result = new List<Integer>();
        Deque<int> deque = new Deque<int>();

        for (int i = 0; i < n; i++) {
            // Remove elements not in the current window
            if (deque.Count > 0 && deque.Peek() < i - k + 1) {
                deque.Dequeue();
            }

            // Remove elements smaller than the current element
            while (deque.Count > 0 && data[deque.PeekLast()] < data[i]) {
                deque.RemoveLast();
            }

            // Add current element's index
            deque.Enqueue(i);

            // Add the maximum for the current window
            if (i >= k - 1) {
                result.Add(data[deque.Peek()]);
            }
        }

        return result;
    }
}
